#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res;
}
const int N=1e5+10;
int a[N][5],dp[N][5],s[N],cur[5];
signed main()
{
	int n=read();rep(1,3,i)rep(1,n,j)s[j]+=a[j][i]=read();
	dp[0][1]=0;dp[1][1]=a[1][1];dp[1][2]=a[1][1]+a[1][2];dp[1][3]=s[1];
	rep(2,n,i)
	{
		rep(1,3,j)cur[j]=dp[i-1][j]+a[i][j];
		dp[i][2]=max(cur[1]+a[i][2],max(cur[3]+a[i][2],cur[2]));
		dp[i][1]=max(dp[i-2][3]+s[i]+s[i-1],max(cur[2]+a[i][1],max(cur[3]+a[i][1]+a[i][2],cur[1])));
		dp[i][3]=max(dp[i-2][1]+s[i]+s[i-1],max(cur[2]+a[i][3],max(cur[1]+a[i][3]+a[i][2],cur[3])));
	}
//	rep(0,n,i)printf("%d %d %d\n",dp[i][1],dp[i][2],dp[i][3]);
	printf("%lld\n",dp[n][3]);return 0;
}
